/**
 * Self-contained cross-reduction scan test.
 *
 * Run:
 *   pnpm run gnode -- run open-source/gnosis/src/__tests__/reduction-projection-scan.test.ts
 */

import assert from 'node:assert';
import { buildReport, missingBackpressure } from '../flow-obstruction';
import { scanCoreReductionFamilies } from '../reduction-projection-scan';

const obstructionReport = buildReport(
  'queue-loop',
  [missingBackpressure(4)],
  4
);

const result = scanCoreReductionFamilies({
  voidSignals: [
    {
      dimension: 'cross_file',
      visibleCrossings: 0,
      intermoduleEdges: 2,
      exactWitness: false,
    },
  ],
  untanglingSignals: [
    {
      crossingNumber: 11,
      beta1: 2,
      violationPaths: 3,
      defectFamily: 'composite',
    },
  ],
  contagionSignals: [
    {
      mesh: { peers: 5, hops: 3 },
      vector: {
        payloadId: 'viral-state',
        momentum: 3,
        relayFriction: 2,
      },
    },
  ],
  obstructionSignals: [
    {
      report: obstructionReport,
    },
  ],
  triangulationSignals: [
    {
      idPrefix: 'tri-coerce',
      mesh: {
        vertices: 6,
        edges: 12,
        faces: 8,
      },
      dimensions: [2, 3, 6, 54],
    },
  ],
});

assert.strictEqual(result.reductions.length, 16);
assert.strictEqual(result.scans.length, 16);

const byId = new Map(result.scans.map((scan) => [scan.id, scan]));

const voidScan = byId.get('void:cross_file');
assert.ok(voidScan);
assert.strictEqual(voidScan!.shapeUnit.isProjectionParadox, true);
assert.strictEqual(voidScan!.sandwich.withinBounds, true);

const untanglingScan = byId.get('untangling:staged-expand-first');
assert.ok(untanglingScan);
assert.strictEqual(untanglingScan!.shapeUnit.isProjectionParadox, true);
assert.strictEqual(untanglingScan!.predictive.consistent, true);

const contagionScan = byId.get('contagion:viral-state');
assert.ok(contagionScan);
assert.strictEqual(contagionScan!.shapeUnit.isProjectionParadox, true);
assert.strictEqual(contagionScan!.sandwich.withinBounds, true);

const obstructionScan = byId.get('obstruction:queue-loop');
assert.ok(obstructionScan);
assert.strictEqual(obstructionScan!.shapeUnit.isProjectionParadox, true);
assert.strictEqual(obstructionScan!.predictive.consistent, true);

const triScan = byId.get('tri-coerce:2->54');
assert.ok(triScan);
assert.strictEqual(triScan!.shapeUnit.isProjectionParadox, true);
assert.strictEqual(triScan!.sandwich.withinBounds, true);
assert.strictEqual(triScan!.predictive.consistent, true);

const triScanReverse = byId.get('tri-coerce:54->2');
assert.ok(triScanReverse);
assert.strictEqual(triScanReverse!.shapeUnit.isProjectionParadox, false);
assert.strictEqual(triScanReverse!.sandwich.withinBounds, true);
assert.strictEqual(triScanReverse!.predictive.consistent, true);

console.log('reduction-projection-scan: all tests passed');
